    map<string, int> fileMap; // Map to store file IDs and sizes
    vector<string> fileNames; // Vector to store file names

public:
    // Method to create a file with a unique ID and specified size
    void createFile(const string& fileName, int fileSize) {
        string fileId = "file_" + to_string(fileNames.size() + 1);
        fileMap[fileId] = fileSize;
        fileNames.push_back(fileName);
    }

    // Method to delete a file by ID
    void deleteFile(const string& fileId) {
        if (fileMap.find(fileId) != fileMap.end()) {
            fileMap.erase(fileId);
            fileNames.erase(remove(fileNames.begin(), fileNames.end(), fileId), fileNames.end());
        }
    }

    // Method to list all files and their sizes
    void listFiles() {
        for (const auto& pair : fileMap) {
            cout << "File ID: " << pair.first << ", Size: " << pair.second << " bytes" << endl;
        }
    }
};

