fn string_compression(s: &str) -> String {
    if s.is_empty() {
        return s.to_string();
    }

    let mut result = String::new();
    let mut current_char = s.chars().next().unwrap();
    let mut count = 1;

    for c in s.chars().skip(1) {
        if c == current_char {
            count += 1;
        } else {
            result.push_str(&format!("{}{}", current_char, count));
            current_char = c;
            count = 1;
        }
    }

    result.push_str(&format!("{}{}", current_char, count));
    if result.len() >= s.len() {
        return s.to_string();
    }

    result
}

