	shortURL    string
	urlMap      map[string]string
}

func NewURLShortener() *URLShortener {
	return &URLShortener{
		urlMap: make(map[string]string),
	}
}

func (u *URLShortener) StoreURL(originalURL string) error {
	if originalURL == "" {
		return errors.New("empty original URL")
	}

	// Generate a short URL
	shortURL := generateShortURL()
	u.originalURL = originalURL
	u.shortURL = shortURL
	u.urlMap[shortURL] = originalURL

	return nil
}

func (u *URLShortener) RetrieveURL(shortURL string) (string, error) {
	if shortURL == "" {
		return "", errors.New("empty short URL")
	}

	if _, exists := u.urlMap[shortURL]; !exists {
		return "", errors.New("short URL not found")
	}

	return u.urlMap[shortURL], nil
}

func generateShortURL() string {
	rand.Seed(time.Now().UnixNano())
	length := 6
	shortURL := strings.Repeat("0123456789", length)
	for i := 0; i < length; i++ {
		char := rune(rand.Intn(10))
		shortURL = strings.Replace(shortURL, string([]rune(shortURL)[i]), string(char), 1)
	}
	return shortURL
}

